proof_block:
// The ensures has the shape `(antecedent) ==> det_set_equal(...)`. The
// antecedent (both `=~=` on `.seq@` and both `.wf()`s) is NOT a free hypothesis
// at the prelude point: that's why the prior attempt's bare assertions about
// `post*.seq@` looked fine inside the `if` but the final postcondition still
// failed. We keep the outer `if (antecedent) { ... }` so each conjunct becomes a
// hypothesis inside the branch, and additionally broadcast the vstd array
// axioms (`axiom_array_ext_equal`, `lemma_array_index`) so z3 has the linkage
// between `[A; N]`, `array_view`, and pointwise indexing that `det_set_equal`
// reduces to.
broadcast use vstd::array::group_array_axioms;

if ({
    &&& (post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
    &&& (post1_self_.wf())
    &&& (post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
    &&& (post2_self_.wf())
}) {
    // Common target both ensures pin `.seq@` to.
    let target = pre_self_.seq@.update(i as int, out);

    // (1) Materialize both `=~=` ensures into concrete Seq `==` via the
    //     shared witness `target`.
    assert(post1_self_.seq@ =~= target);
    assert(post2_self_.seq@ =~= target);
    assert(post1_self_.seq@ == target);
    assert(post2_self_.seq@ == target);

    // (2) Length comes from `wf()` and from `Seq::update` preserving length.
    assert(target.len() == N as int);
    assert(post1_self_.seq@.len() == N as int);
    assert(post2_self_.seq@.len() == N as int);
    assert(post1_self_.seq@.len() == post2_self_.seq@.len());

    // (3) Pointwise: at every in-range j, both views agree (both equal
    //     `target[j]`). The two explicit indexings below instantiate the
    //     two disjoint `Seq` triggers `post1_self_.seq@[j]` and
    //     `post2_self_.seq@[j]` on a common `j`.
    assert forall|j: int| 0 <= j < N as int
        implies post1_self_.seq@[j] == post2_self_.seq@[j] by {
        assert(post1_self_.seq@[j] == target[j]);
        assert(post2_self_.seq@[j] == target[j]);
    };

    // (4) Lift pointwise to full Seq via Seq extensionality `=~=`.
    assert(post1_self_.seq@ =~= post2_self_.seq@);
    assert(post1_self_.seq@ == post2_self_.seq@);

    // (5) `Ghost<Seq<A>>` equality reduces to inner-value equality.
    assert(post1_self_.seq =~= post2_self_.seq);
    assert(post1_self_.seq == post2_self_.seq);

    // (6) `view` is `#[verifier(inline)]` and returns `self.seq@`, so view
    //     equality is exactly the seq-field-view equality.
    assert(post1_self_@ =~= post2_self_@);
    assert(post1_self_@ == post2_self_@);

    // (7) Unit return: both `()`, trivially equal.
    assert(r1 == r2);
}
